<?php namespace App\Repositories\Hostel;use App\Repositories\BaseRepository;use App\Models\Hostel\HostelAllocation;use Illuminate\Database\Eloquent\Collection;class HostelAllocationRepository extends BaseRepository{    public function __construct(HostelAllocation $model)    {        $this->model = $model;        parent::__construct($model);    }    public function findByStudent(int $studentId): ?HostelAllocation    {        return $this->query()->where('student_id', $studentId)->where('status', 'active')->first();    }    public function findByRoom(int $roomId): Collection    {        return $this->findByField('hostel_room_id', $roomId);    }    public function findByHostel(int $hostelId): Collection    {        return $this->findByField('hostel_id', $hostelId);    }    public function getActiveAllocations(): Collection    {        return $this->query()->where('status', 'active')->get();    }    public function getByAcademicYear(int $academicYearId): Collection    {        return $this->findByField('academic_year_id', $academicYearId);    }    public function allocate(int $studentId, int $hostelId, int $roomId, array $data = []): HostelAllocation    {        $data['student_id'] = $studentId;        $data['hostel_id'] = $hostelId;        $data['hostel_room_id'] = $roomId;        $data['allocation_date'] = $data['allocation_date'] ?? now();        $data['status'] = 'active';        return $this->create($data);    }    public function deallocate(int $allocationId): bool    {        return $this->update($allocationId, [            'status' => 'ended',            'end_date' => now(),        ]);    }    public function getByGender(string $gender): Collection    {        return $this->findByField('gender', $gender);    }    public function countByHostel(): Collection    {        return $this->query()->selectRaw('hostel_id, COUNT(*) as total')->where('status', 'active')->groupBy('hostel_id')->get();    }    public function getCurrentOccupancy(int $hostelId): int    {        return $this->query()->where('hostel_id', $hostelId)->where('status', 'active')->count();    }}